import React, { useState } from 'react';
import { Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { ProductionStageDto, StageTrackingDto } from '../../../services/sx/models';
import { formatDateLocal, formatNumber } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const TRACKING_STATUS: Record<string, string> = {
  Pending: 'Chờ QC',
  QcApproved: 'Đã duyệt',
  QcRejected: 'Từ chối',
};

const DinhMucKhoanPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);

  const [fromDate, setFromDate] = useState(monthStart);
  const [toDate, setToDate] = useState(monthEnd);
  const [stageId, setStageId] = useState('');
  const [stages, setStages] = useState<ProductionStageDto[]>([]);
  const [rows, setRows] = useState<StageTrackingDto[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      sxService.getStages().then(s => { if (!cancelled) setStages(s); }).catch(err => {
          if (!cancelled) dispatch(addToast({ message: getApiErrorMessage(err, 'Không tải được dữ liệu danh mục. Vui lòng thử lại.'), type: 'error' }));
        });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getStageTracking({
          stageId: stageId || undefined,
          fromDate,
          toDate,
          page: 1,
          pageSize: 200,
        })
        .then(res => { if (!cancelled) setRows(res.items); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải báo cáo', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [fromDate, toDate, stageId, dispatch, reloadKey]);

  const totalOut = rows.reduce((a, r) => a + r.outQty, 0);
  const totalDefect = rows.reduce((a, r) => a + r.defectQty, 0);

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-chart-bar" /> Định mức khoán (theo dõi công đoạn)</h1>
          <p className={styles.subtitle}>Báo cáo chỉ đọc — dữ liệu theo dõi sản lượng theo công đoạn</p>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-dinh-muc-khoan-filters`}>
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          onChange={(v: DateRangeValue) => { setFromDate(v.fromDate ?? ''); setToDate(v.toDate ?? ''); }}
        />
        <Select
          value={stageId}
          onChange={e => setStageId(e.target.value)}
          options={[
            { value: '', label: 'Tất cả công đoạn' },
            ...stages.map(s => ({ value: s.id, label: `${s.code} — ${s.name}` })),
          ]}
          size="small"
        />
      </div>

      <div className={styles.summaryBar}>
        <div className={styles.summaryItem}><label className={styles.label}>Tổng SL ra</label><strong>{formatNumber(totalOut)}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>Tổng SL lỗi</label><strong>{formatNumber(totalDefect)}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>Số dòng</label><strong>{rows.length}</strong></div>
        <ListSearchRefreshButtons testIdPrefix="erp-dinh-muc-khoan" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : rows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu trong kỳ</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Ngày</th>
                  <th>LSX</th>
                  <th>Công đoạn</th>
                  <th className={styles.colRight}>SL vào</th>
                  <th className={styles.colRight}>SL ra</th>
                  <th className={styles.colRight}>SL lỗi</th>
                  <th>Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                {rows.map(r => (
                  <tr key={r.id}>
                    <td>{formatDateLocal(r.trackingDate)}</td>
                    <td><code>{r.productionOrderCode}</code></td>
                    <td>{r.stageName}</td>
                    <td className={styles.colRight}>{formatNumber(r.inQty)}</td>
                    <td className={styles.colRight}>{formatNumber(r.outQty)}</td>
                    <td className={styles.colRight}>{formatNumber(r.defectQty)}</td>
                    <td><span className={styles.tagDefault}>{TRACKING_STATUS[r.status] ?? r.status}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default DinhMucKhoanPage;
